@namespace sv_a1acc30f78dc436bbae77d208dae06be.Components.JobApplication
@using sv_a1acc30f78dc436bbae77d208dae06be.Models

<h4>Review & Submit</h4>
<p class="text-muted">Please review your application before submitting.</p>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@if (SubmittedId.HasValue)
{
    <div class="alert alert-success">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p class="mb-0">Your application has been submitted successfully. Your application ID is <strong>@SubmittedId</strong>.</p>
    </div>
}
else
{
    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3">
                    <h6>@entry.Title at @entry.Company</h6>
                    <div class="text-muted small">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Relationship<br />
                    <span class="text-muted">@r.Email · @r.Phone</span>
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<int> OnEditStep { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public Func<Task<int>> OnSubmit { get; set; } = default!;

    private bool IsSubmitting;
    private int? SubmittedId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        ErrorMessage = null;
        IsSubmitting = true;
        try
        {
            SubmittedId = await OnSubmit();
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

@namespace sv_a1acc30f78dc436bbae77d208dae06be.Components.JobApplication

<nav class="step-indicator" aria-label="Application progress">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var stepIndex = i;
            var status = stepIndex < CurrentStep ? "completed"
                       : stepIndex == CurrentStep ? "current"
                       : "upcoming";
            <li class="step-item @status">
                @if (status == "completed")
                {
                    <button class="step-button" @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-badge">✓</span>
                        <span class="step-label">@StepNames[stepIndex]</span>
                    </button>
                }
                else
                {
                    <span class="step-button" aria-current="@(status == "current" ? "step" : null)">
                        <span class="step-badge">@(stepIndex + 1)</span>
                        <span class="step-label">@StepNames[stepIndex]</span>
                    </span>
                }
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }
}

.step-indicator {
    margin-bottom: 2rem;
}

.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    counter-reset: step;
}

.step-item {
    flex: 1;
    text-align: center;
    position: relative;
}

.step-item + .step-item::before {
    content: "";
    position: absolute;
    top: 16px;
    left: -50%;
    width: 100%;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step-item.completed + .step-item::before {
    background: #198754;
}

.step-button {
    display: inline-flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
    background: none;
    border: none;
    cursor: default;
    position: relative;
    z-index: 1;
    padding: 0;
    font: inherit;
    color: inherit;
}

.completed .step-button {
    cursor: pointer;
}

.completed .step-button:hover .step-label {
    text-decoration: underline;
}

.step-badge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 32px;
    height: 32px;
    border-radius: 50%;
    font-weight: 600;
    font-size: 0.875rem;
    background: #e9ecef;
    color: #6c757d;
}

.completed .step-badge {
    background: #198754;
    color: white;
}

.current .step-badge {
    background: #0d6efd;
    color: white;
}

.step-label {
    font-size: 0.8rem;
    color: #6c757d;
}

.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.completed .step-label {
    color: #198754;
}

