    gap: 0.5rem;
    background: none;
    border: none;
    cursor: default;
    position: relative;
    z-index: 1;
    padding: 0;
    font: inherit;
    color: inherit;
}

.completed .step-button {
    cursor: pointer;
}

.completed .step-button:hover .step-label {
    text-decoration: underline;
}

.step-badge {
