        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }
}

.step-indicator {
    margin-bottom: 2rem;
}

.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    counter-reset: step;
}

.step-item {
    flex: 1;
    text-align: center;
    position: relative;
}

.step-item + .step-item::before {
    content: "";
    position: absolute;
    top: 16px;
    left: -50%;
    width: 100%;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step-item.completed + .step-item::before {
    background: #198754;
}

.step-button {
    display: inline-flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
    background: none;
    border: none;
    cursor: default;
    position: relative;
    z-index: 1;
    padding: 0;
    font: inherit;
    color: inherit;
}

.completed .step-button {
    cursor: pointer;
}

.completed .step-button:hover .step-label {
    text-decoration: underline;
}

.step-badge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 32px;
    height: 32px;
    border-radius: 50%;
    font-weight: 600;
    font-size: 0.875rem;
    background: #e9ecef;
    color: #6c757d;
}

.completed .step-badge {
    background: #198754;
    color: white;
}

.current .step-badge {
    background: #0d6efd;
    color: white;
}

.step-label {
    font-size: 0.8rem;
    color: #6c757d;
}

.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.completed .step-label {
    color: #198754;
}

