@page "/apply"
@rendermode InteractiveServer
@using sv_a1acc30f78dc436bbae77d208dae06be.Components.JobApplication
@using sv_a1acc30f78dc436bbae77d208dae06be.Models
@using sv_a1acc30f78dc436bbae77d208dae06be.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="personalInfo"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="NextStep" />
            break;
        case 1:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 2:
            <ReferencesStep References="references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;
        case 3:
            <CoverLetterStep CoverLetter="@coverLetter"
                             CoverLetterChanged="v => coverLetter = v"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 4:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="@coverLetter"
                        OnEditStep="GoToStep"
                        OnBack="PreviousStep"
                        OnSubmit="SubmitAsync" />
            break;
    }
</div>

@code {
    private int currentStep;
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private void NextStep() => currentStep++;
    private void PreviousStep() => currentStep--;
    private void GoToStep(int step) => currentStep = step;

    private async Task<int> SubmitAsync()
    {
        var application = new JobApplication(
            personalInfo.ToRecord(),
            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
            references.Select(r => r.ToRecord()).ToList(),
            coverLetter
        );

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

